471→        y: rawPivot.y + (primaryAxis.y * endAlong),
472→      },
473→      {
474→        rawPivot,
475→        axis: primaryAxis,
476→        rotationDegrees,
477→        translation,
478→        lengthScale,
479→      }
480→    ),
481→    resizable,
482→    rotationDegrees,
483→  };
484→}
