 30→function uniqueOutlinePoints(points = []) {
 31→  const unique = [];
 32→  for (const point of points) {
 33→    if (!Number.isFinite(point?.x) || !Number.isFinite(point?.z)) continue;
 34→    const previous = unique[unique.length - 1];
 35→    if (!previous || distance2d(previous, point) > EPSILON) {
