211→    { x: metrics.span + metrics.overhangEnd, z: 0, kind: 'overhang' },
212→  ];
213→
214→  const topNodes = createLocalNodeMap(topPoints, 'top');
215→  const bottomNodes = createLocalNodeMap(bottomPoints, 'bottom');
216→  const overhangNodes = createLocalNodeMap(overhangPoints, 'overhang');
217→  const members = [];
218→
219→  addMember(members, overhangNodes[0].id, topNodes[0].id, 'topChord', members.length);
220→  for (let index = 0; index < topNodes.length - 1; index += 1) {
221→    addMember(members, topNodes[index].id, topNodes[index + 1].id, 'topChord', members.length);
222→  }
223→  addMember(members, topNodes[topNodes.length - 1].id, overhangNodes[1].id, 'topChord', members.length);
224→
225→  for (let index = 0; index < bottomNodes.length - 1; index += 1) {
226→    addMember(members, bottomNodes[index].id, bottomNodes[index + 1].id, 'bottomChord', members.length);
227→  }
228→
229→  for (let index = 1; index < bottomNodes.length - 1; index += 1) {
230→    addMember(members, bottomNodes[index].id, topNodes[index].id, 'web', members.length);
231→  }
232→
233→  const midpoint = Math.floor(metrics.panelCount / 2);
234→  for (let index = 0; index < metrics.panelCount; index += 1) {
235→    if (index < midpoint) {
236→      addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
237→      continue;
238→    }
239→    addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
240→  }
241→
242→  return {
243→    nodes: [...overhangNodes, ...topNodes, ...bottomNodes],
244→    members,
245→    roofOutline: [
246→      { x: -metrics.overhangStart, z: 0 },
247→      ...topPoints,
248→      { x: metrics.span + metrics.overhangEnd, z: 0 },
249→    ],
250→    bottomOutline: bottomPoints,
251→    topChordRuns: [
252→      { id: 'left', side: 'left', points: topPoints.slice(0, midpoint + 1) },
253→      { id: 'right', side: 'right', points: topPoints.slice(midpoint).reverse() },
254→    ],
255→  };
256→}
