331→function buildBoxGableProfile(metrics) {
332→  const crownWidth = Math.max(metrics.span * 0.22, Math.min(metrics.span * 0.3, 1200));
333→  const crownStart = (metrics.span - crownWidth) / 2;
334→  const crownEnd = crownStart + crownWidth;
335→  const structuralOutline = uniqueOutlinePoints([
336→    { x: 0, z: 0 },
337→    { x: crownStart, z: metrics.rise },
338→    { x: crownEnd, z: metrics.rise },
339→    { x: metrics.span, z: 0 },
340→  ]);
341→
342→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
343→    webMode: 'gable',
344→    topChordRuns: [
345→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 2) },
346→      { id: 'right', side: 'right', points: [structuralOutline[3], structuralOutline[2]] },
347→    ],
348→  });
349→}
350→
351→function buildHipSliceProfile(metrics, options = {}) {
352→  const supportLength = Math.max(Number(options.supportLength || 0), 0);
353→  const layoutOffset = Math.max(Number(options.layoutOffset || 0), 0);
354→  const halfSpan = Math.max(metrics.span / 2, EPSILON);
355→  const endDistance = supportLength > EPSILON
356→    ? Math.max(0, Math.min(layoutOffset, supportLength - layoutOffset))
357→    : halfSpan;
358→  const clippedRun = Math.max(0, Math.min(halfSpan, endDistance));
359→  const localRise = metrics.rise * (clippedRun / halfSpan);
360→
361→  if (clippedRun <= EPSILON || localRise <= EPSILON) {
362→    return buildFlatProfile({
363→      ...metrics,
364→      rise: 0,
365→    });
366→  }
367→
368→  if (clippedRun >= halfSpan - EPSILON) {
369→    return buildGableProfile(metrics);
370→  }
371→
372→  const crownStart = clippedRun;
373→  const crownEnd = metrics.span - clippedRun;
374→  const structuralOutline = uniqueOutlinePoints([
375→    { x: 0, z: 0 },
376→    { x: crownStart, z: localRise },
377→    { x: crownEnd, z: localRise },
378→    { x: metrics.span, z: 0 },
379→  ]);
380→
381→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
382→    webMode: 'gable',
383→    topChordRuns: [
384→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 2) },
385→      { id: 'right', side: 'right', points: [structuralOutline[3], structuralOutline[2]] },
386→    ],
387→  });
388→}
389→
390→function buildHipProfile(metrics) {
391→  return buildGableProfile(metrics);
392→}
393→
394→function buildDroppedEavesProfile(metrics) {
395→  const heelInset = Math.max(metrics.span * 0.12, Math.min(metrics.span * 0.18, 900));
396→  const heelHeight = Math.max(metrics.rise * 0.32, 250);
397→  const structuralOutline = uniqueOutlinePoints([
398→    { x: 0, z: 0 },
399→    { x: heelInset, z: heelHeight },
400→    { x: metrics.span / 2, z: metrics.rise },
401→    { x: metrics.span - heelInset, z: heelHeight },
402→    { x: metrics.span, z: 0 },
403→  ]);
404→
405→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
406→    webMode: 'gable',
407→    topChordRuns: [
408→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 3) },
409→      { id: 'right', side: 'right', points: [structuralOutline[4], structuralOutline[3], structuralOutline[2]] },
410→    ],
411→  });
412→}
413→
414→function buildPyramidHippedProfile(metrics) {
415→  const ridgeWidth = Math.max(metrics.span * 0.08, Math.min(metrics.span * 0.14, 700));
416→  const ridgeStart = (metrics.span - ridgeWidth) / 2;
417→  const ridgeEnd = ridgeStart + ridgeWidth;
418→  const shoulderHeight = Math.max(metrics.rise * 0.82, 300);
419→  const shoulderInset = Math.max(metrics.span * 0.08, Math.min(metrics.span * 0.12, 600));
420→  const structuralOutline = uniqueOutlinePoints([
421→    { x: 0, z: 0 },
422→    { x: ridgeStart - shoulderInset, z: shoulderHeight },
423→    { x: ridgeStart, z: metrics.rise },
424→    { x: ridgeEnd, z: metrics.rise },
425→    { x: ridgeEnd + shoulderInset, z: shoulderHeight },
426→    { x: metrics.span, z: 0 },
427→  ]);
428→
429→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
430→    webMode: 'gable',
431→    topChordRuns: [
432→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 3) },
433→      { id: 'right', side: 'right', points: [structuralOutline[5], structuralOutline[4], structuralOutline[3]] },
434→    ],
435→  });
436→}
437→
438→function buildDomedProfile(metrics) {
439→  const segments = Math.max(metrics.panelCount * 6, 48);
440→  const structuralOutline = uniqueOutlinePoints(Array.from({ length: segments + 1 }, (_, index) => {
441→    const ratio = index / segments;
442→    const x = metrics.span * ratio;
443→    const z = metrics.rise * Math.sin(Math.PI * ratio);
444→    return {
445→      x,
446→      z: Math.max(0, z),
447→    };
448→  }));
449→
450→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
451→    webMode: 'gable',
452→    topChordRuns: [{
453→      id: 'main',
454→      side: 'main',
455→      points: structuralOutline,
456→      measurementCurve: {
457→        kind: 'sine_arch',
458→        startX: 0,
459→        endX: metrics.span,
460→        rise: metrics.rise,
461→      },
462→    }],
463→  });
464→}
