466→export function buildTrussProfile(instance, catalog, options = {}) {
467→  const trussType = resolveTrussType(instance?.trussTypeId, catalog);
468→  const metrics = resolveTrussMetrics(instance, trussType);
469→  const shape = metrics.shape || trussType.shape || metrics.family;
470→
471→  let profile;
472→  switch (shape) {
473→    case 'flat':
474→      profile = buildFlatProfile(metrics);
475→      break;
476→    case 'hip':
477→      profile = Number.isFinite(options?.layoutOffset) && Number.isFinite(options?.supportLength)
478→        ? buildHipSliceProfile(metrics, options)
479→        : buildHipProfile(metrics);
480→      break;
481→    case 'box_gable':
482→      profile = buildBoxGableProfile(metrics);
483→      break;
484→    case 'pyramid_hipped':
485→      profile = buildPyramidHippedProfile(metrics);
486→      break;
487→    case 'domed':
488→      profile = buildDomedProfile(metrics);
489→      break;
490→    case 'dropped_eaves':
491→      profile = buildDroppedEavesProfile(metrics);
492→      break;
493→    case 'shed':
494→      profile = buildShedProfile(metrics);
495→      break;
496→    case 'gable':
497→    default:
498→      profile = buildGableProfile(metrics);
499→      break;
500→  }
501→
502→  return {
503→    trussType,
504→    metrics,
505→    ...profile,
506→  };
507→}
