  1→const EPSILON = 1e-6;
  2→const SINE_ARCH_INTEGRATION_STEPS = 256;
  3→const SINE_ARCH_BINARY_SEARCH_STEPS = 28;
  4→
  5→function clamp(value, min, max) {
  6→  return Math.max(min, Math.min(max, value));
  7→}
  8→
  9→function normalize2d(vector) {
 10→  const length = Math.sqrt((vector.x * vector.x) + (vector.z * vector.z));
 11→  if (length <= EPSILON) {
 12→    return { x: 1, z: 0 };
 13→  }
 14→
 15→  return {
 16→    x: vector.x / length,
 17→    z: vector.z / length,
 18→  };
 19→}
 20→
 21→function distance2d(start, end) {
 22→  const dx = end.x - start.x;
 23→  const dz = end.z - start.z;
 24→  return Math.sqrt((dx * dx) + (dz * dz));
 25→}
 26→
 27→export function polylineLength(points = []) {
 28→  let total = 0;
 29→  for (let index = 0; index < points.length - 1; index += 1) {
 30→    total += distance2d(points[index], points[index + 1]);
 31→  }
 32→  return total;
 33→}
 34→
 35→export function samplePolyline(points = [], distanceAlong = 0) {
 36→  if (!points.length) return null;
 37→  if (points.length === 1) {
 38→    return {
 39→      point: { ...points[0] },
 40→      tangent: { x: 1, z: 0 },
 41→      distanceAlong: 0,
 42→    };
 43→  }
 44→
 45→  const totalLength = polylineLength(points);
 46→  let remaining = clamp(distanceAlong, 0, totalLength);
 47→
 48→  for (let index = 0; index < points.length - 1; index += 1) {
 49→    const start = points[index];
 50→    const end = points[index + 1];
 51→    const segmentLength = distance2d(start, end);
 52→    if (segmentLength <= EPSILON) continue;
 53→
 54→    if (remaining <= segmentLength + EPSILON || index === points.length - 2) {
 55→      const ratio = clamp(remaining / segmentLength, 0, 1);
 56→      return {
 57→        point: {
 58→          x: start.x + ((end.x - start.x) * ratio),
 59→          z: start.z + ((end.z - start.z) * ratio),
 60→        },
 61→        tangent: normalize2d({
 62→          x: end.x - start.x,
 63→          z: end.z - start.z,
 64→        }),
 65→        distanceAlong: clamp(distanceAlong, 0, totalLength),
 66→      };
 67→    }
 68→
 69→    remaining -= segmentLength;
 70→  }
 71→
 72→  const lastPoint = points[points.length - 1];
 73→  const previousPoint = points[points.length - 2] || lastPoint;
 74→  return {
 75→    point: { ...lastPoint },
 76→    tangent: normalize2d({
 77→      x: lastPoint.x - previousPoint.x,
 78→      z: lastPoint.z - previousPoint.z,
 79→    }),
 80→    distanceAlong: totalLength,
 81→  };
 82→}
 83→
 84→function evaluateSineArchPoint(curve, x) {
 85→  const span = Math.max(Number(curve?.endX || 0) - Number(curve?.startX || 0), EPSILON);
 86→  const rise = Number(curve?.rise || 0);
 87→  const startX = Number(curve?.startX || 0);
 88→  const ratio = (x - startX) / span;
 89→
 90→  return {
 91→    x,
 92→    z: rise * Math.sin(Math.PI * clamp(ratio, 0, 1)),
 93→  };
 94→}
 95→
 96→function evaluateSineArchDerivative(curve, x) {
 97→  const span = Math.max(Number(curve?.endX || 0) - Number(curve?.startX || 0), EPSILON);
 98→  const rise = Number(curve?.rise || 0);
 99→  const startX = Number(curve?.startX || 0);
100→  const ratio = (x - startX) / span;
101→  return (rise * Math.PI / span) * Math.cos(Math.PI * clamp(ratio, 0, 1));
102→}
103→
104→function integrateSimpson(fn, start, end, steps = SINE_ARCH_INTEGRATION_STEPS) {
105→  const evenSteps = Math.max(2, steps + (steps % 2));
106→  const h = (end - start) / evenSteps;
107→  let sum = fn(start) + fn(end);
108→
109→  for (let index = 1; index < evenSteps; index += 1) {
110→    const x = start + (index * h);
111→    sum += fn(x) * (index % 2 === 0 ? 2 : 4);
112→  }
113→
114→  return (h / 3) * sum;
115→}
116→
117→function getSineArchLengthAtX(curve, x) {
118→  const startX = Number(curve?.startX || 0);
119→  const endX = Number(curve?.endX || 0);
120→  const clampedX = clamp(x, startX, endX);
121→  if (clampedX <= startX + EPSILON) return 0;
122→
123→  return integrateSimpson((value) => {
124→    const dzdx = evaluateSineArchDerivative(curve, value);
125→    return Math.sqrt(1 + (dzdx * dzdx));
126→  }, startX, clampedX);
127→}
128→
129→export function getMeasurementCurveLength(curve = null) {
130→  if (!curve) return 0;
131→  if (curve.kind === 'sine_arch') {
132→    return getSineArchLengthAtX(curve, Number(curve.endX || 0));
133→  }
134→  return 0;
135→}
136→
137→export function sampleMeasurementCurve(curve = null, distanceAlong = 0) {
138→  if (!curve) return null;
139→
140→  if (curve.kind === 'sine_arch') {
141→    const startX = Number(curve?.startX || 0);
142→    const endX = Number(curve?.endX || 0);
143→    const totalLength = getMeasurementCurveLength(curve);
144→    const targetLength = clamp(distanceAlong, 0, totalLength);
145→
146→    let low = startX;
147→    let high = endX;
148→    for (let index = 0; index < SINE_ARCH_BINARY_SEARCH_STEPS; index += 1) {
149→      const midpoint = (low + high) / 2;
150→      const midpointLength = getSineArchLengthAtX(curve, midpoint);
151→      if (midpointLength < targetLength) {
152→        low = midpoint;
153→      } else {
154→        high = midpoint;
155→      }
156→    }
157→
158→    const sampleX = (low + high) / 2;
159→    const point = evaluateSineArchPoint(curve, sampleX);
160→    const tangent = normalize2d({
161→      x: 1,
162→      z: evaluateSineArchDerivative(curve, sampleX),
163→    });
164→
165→    return {
166→      point,
167→      tangent,
168→      distanceAlong: targetLength,
169→    };
170→  }
171→
172→  return null;
173→}
174→
175→export function getTopChordRunLength(run = null) {
176→  const points = run?.points || [];
177→  if (run?.measurementCurve) {
178→    return getMeasurementCurveLength(run.measurementCurve);
179→  }
180→  return polylineLength(points);
181→}
182→
183→export function sampleTopChordRun(run = null, distanceAlong = 0) {
184→  if (!run) return null;
185→  if (run.measurementCurve) {
186→    return sampleMeasurementCurve(run.measurementCurve, distanceAlong);
187→  }
188→  return samplePolyline(run.points || [], distanceAlong);
189→}
190→
191→export function sampleTopChordRunMidpoint(run = null) {
192→  return sampleTopChordRun(run, getTopChordRunLength(run) / 2);
193→}
