 41→function dedupeAttachments(attachments = []) {
 42→  return attachments.filter((attachment, index) => (
 43→    attachments.findIndex((entry) => (
 44→      Math.abs(entry.localPoint.x - attachment.localPoint.x) <= EPSILON
 45→      && Math.abs(entry.localPoint.z - attachment.localPoint.z) <= EPSILON
 46→    )) === index
 47→  ));
 48→}
