function selectOutwardNormal(normal, midpoint, spanMidpoint) {
  const preferred = midpoint.x < spanMidpoint
    ? { x: -1, y: 0 }
    : { x: 1, y: 0 };
  const alignment = (normal.x * preferred.x) + (normal.y * preferred.y);

  return alignment >= 0
    ? normal
    : { x: -normal.x, y: -normal.y };
}

function extendDetailBounds(detailBounds, dimensions = [], tags = []) {
  const bounds = {
    minX: detailBounds.minX,
    maxX: detailBounds.maxX,
    minY: -detailBounds.maxZ,
    maxY: -detailBounds.minZ,
  };

  for (const figure of dimensions) {
    const figureBounds = estimateDimensionBounds(figure);
    if (!figureBounds) continue;
    bounds.minX = Math.min(bounds.minX, figureBounds.minX);
    bounds.maxX = Math.max(bounds.maxX, figureBounds.maxX);
    bounds.minY = Math.min(bounds.minY, figureBounds.minY);
    bounds.maxY = Math.max(bounds.maxY, figureBounds.maxY);
  }

  for (const tag of tags) {
    const tagBounds = estimateTagBounds(tag);
    if (!tagBounds) continue;
    bounds.minX = Math.min(bounds.minX, tagBounds.minX);
    bounds.maxX = Math.max(bounds.maxX, tagBounds.maxX);
    bounds.minY = Math.min(bounds.minY, tagBounds.minY);
    bounds.maxY = Math.max(bounds.maxY, tagBounds.maxY);
  }

  return {
    minX: bounds.minX,
    maxX: bounds.maxX,
    minZ: -bounds.maxY,
    maxZ: -bounds.minY,
  };
}

function resolveDetailCrestPoint(roofOutline = []) {
  if (!roofOutline.length) {
    return { x: 0, z: 0 };
  }

  const maxZ = Math.max(...roofOutline.map((point) => point.z));
  const crestPoints = roofOutline.filter((point) => Math.abs(point.z - maxZ) <= 1e-6);
  const averageX = crestPoints.reduce((sum, point) => sum + point.x, 0) / Math.max(crestPoints.length, 1);

  return {
    x: averageX,
    z: maxZ,
  };
}

