122→function applyCollisionOffsets(tags = []) {
123→  const placed = [];
124→  const offsets = [
125→    { x: 0, y: 0 },
126→    { x: 0, y: -180 },
127→    { x: 0, y: 180 },
128→    { x: 180, y: 0 },
129→    { x: -180, y: 0 },
130→    { x: 160, y: -130 },
131→    { x: -160, y: -130 },
132→  ];
133→
134→  return [...tags]
135→    .sort((a, b) => b.priority - a.priority)
136→    .map((tag) => {
137→      for (const offset of offsets) {
138→        const candidate = {
139→          ...tag,
140→          position: {
141→            x: tag.position.x + offset.x,
142→            y: tag.position.y + offset.y,
143→          },
144→        };
145→        const candidateBounds = estimateTagBounds(candidate);
146→        if (!placed.some((placedTag) => intersects(candidateBounds, placedTag.bounds))) {
147→          placed.push({ bounds: candidateBounds });
148→          return candidate;
149→        }
150→      }
151→
152→      const bounds = estimateTagBounds(tag);
153→      placed.push({ bounds });
154→      return tag;
155→    });
156→}
