 46→  const ordered = [...points].sort((a, b) => a.x - b.x);
 47→  if (x <= ordered[0].x + EPSILON) return { x, z: ordered[0].z };
 48→  if (x >= ordered[ordered.length - 1].x - EPSILON) return { x, z: ordered[ordered.length - 1].z };
