  { x: -250, y: 200 },
  { x: 0, y: -600 },
  { x: 0, y: 600 },
];

function inflateBounds(bounds, gap) {
  return {
    minX: bounds.minX - gap,
    maxX: bounds.maxX + gap,
    minY: bounds.minY - gap,
    maxY: bounds.maxY + gap,
  };
}

function detailBoundsIntersect(a, b) {
  return a.minX < b.maxX && a.maxX > b.minX && a.minY < b.maxY && a.maxY > b.minY;
}

function applyDetailTagCollisionOffsets(tags, fixedObstacles = []) {
  const halfGap = DETAIL_TAG_GAP / 2;
  const placed = fixedObstacles.map((bounds) => inflateBounds(bounds, halfGap));

  return [...tags]
    .sort((a, b) => (b.priority || 0) - (a.priority || 0))
    .map((tag) => {
      for (const offset of DETAIL_TAG_OFFSETS) {
        const candidate = {
          ...tag,
          position: {
            x: tag.position.x + offset.x,
            y: tag.position.y + offset.y,
          },
          leaderLine: tag.leaderLine ? {
            start: tag.leaderLine.start,
            end: {
              x: tag.leaderLine.end.x + offset.x,
              y: tag.leaderLine.end.y + offset.y,
            },
          } : null,
        };
        const candidateBounds = inflateBounds(estimateTagBounds(candidate), halfGap);
        if (!placed.some((placedBounds) => detailBoundsIntersect(candidateBounds, placedBounds))) {
          placed.push(candidateBounds);
          return candidate;
        }
      }
      // Fallback: keep original position if nothing works
      const fallbackBounds = inflateBounds(estimateTagBounds(tag), halfGap);
      placed.push(fallbackBounds);
      return tag;
    });
}
```

Key design choices:
- Reuses `estimateTagBounds` (line 679) which already handles font size, line height, mask padding, text anchor, and rotation.
- Pre-populates `placed` array with dimension figure bounds (as fixed obstacles).
- Sorts by descending priority so pitch/bearing/chord tags get first pick.
- Updates `leaderLine.end` by the same offset as the tag position.
- Falls back to the original position if no collision-free slot is found (same as floor-plan logic).

